 76	    },
 77	    context: account
 78	      ? {
 79	          account: {
 80	            accountId: account._id,
 81	            name: account.name,
 82	            tier: account.tier,
 83	            region: account.region
 84	          },
 85	          contract: { ...account.contract },
 86	          support: {
 87	            supportPlan: account.contract?.supportPlan ?? null,
 88	            openCases: account.context?.openCases ?? null,
 89	            contacts: (account.contacts ?? []).map((contact) => ({
 90	              contactId: contact.contactId,
 91	              role: contact.role,
 92	              email: contact.email
 93	            }))
 94	          },
 95	          invoice: {
 96	            risk: account.context?.invoiceRisk ?? null,
 97	            exposureCents: account.contract?.arrCents ?? null
 98	          },
 99	          usage: {
100	            healthScore: account.context?.healthScore ?? null,
101	            usageTrend: account.context?.usageTrend ?? null
102	          },
103	          shipment: {
104	            status: "delayed",
105	            priority: "high-value",
106	            orderType: "high-value order"
107	          },
108	          regulatory: {
109	            complianceFlags: [...(account.context?.complianceFlags ?? [])],
110	            legalReview: true
111	          },
112	          audit: {
113	            customerVisible: true,
114	            activityIds: activityTimeline.map((item) => item.activityId),
115	            timeline: auditTimeline
116	          }
117	        }
118	      : null,
119	    auditTimeline,
120	    openedAt: at,
121	    updatedAt: at
122	  };
123	  const ownerTasks = ownerGroups.map((ownerGroup, index) => ({
124	    _id: `task-${request._id}-${index + 1}`,
125	    requestId: request._id,
126	    accountId: request.accountId,
127	    ownerGroup,
128	    title: `${ownerGroup} recovery action for ${request.title}`,
129	    status: "open",
130	    dueAt: addHours(at, OWNER_TASK_HORIZON_HOURS[ownerGroup] ?? DEFAULT_TASK_HORIZON_HOURS),
131	    createdAt: at
132	  }));
133	  const customerMessage = {
134	    _id: `msg-${request._id}`,
135	    requestId: request._id,
136	    accountId: request.accountId,
137	    channel: "portal",
138	    visibility: "customer",
139	    audience: "customer",
140	    customerSafe: true,
141	    body: CUSTOMER_SAFE_MESSAGE,
142	    createdAt: at
143	  };
144	  const auditEvents = [
145	    ...activityTimeline.map((item) => ({
146	      _id: `audit-${item.activityId}`,
147	      requestId: request._id,
148	      accountId: request.accountId,
149	      subjectId: request._id,
150	      type: "account.activity.logged",
151	      summary: item.summary,
152	      occurredAt: item.occurredAt,
153	      customerVisible: false,
154	      sequence: item.sequence
155	    })),
156	    {
157	      _id: `audit-${request._id}-customer-visible`,
158	      requestId: request._id,
159	      accountId: request.accountId,
160	      subjectId: request._id,
161	      type: "customer-visible-status",
162	      summary: request.expectedOutcome ?? ESCALATION_STATUS,
163	      actor: "workflow-engine",
164	      ownerGroups: [...ownerGroups],
165	      coordinationGroups: [...COORDINATION_GROUPS],
166	      riskSignals: riskSignals.map((signal) => signal.name),
167	      customerVisible: true,
168	      occurredAt: at,
169	      sequence: auditTimeline.length
170	    }
171	  ];
172	
173	  db.workflow_state = replaceByRequestId(db.workflow_state, request._id, [workflowState]);
174	  db.owner_tasks = replaceByRequestId(db.owner_tasks, request._id, ownerTasks);
175	  db.customer_messages = replaceByRequestId(db.customer_messages, request._id, [customerMessage]);
176	  db.audit_events = replaceByRequestId(db.audit_events, request._id, auditEvents);
177	
178	  return buildPortalView(db);
179	}
180	
181	function replaceByRequestId(collection, requestId, records) {
182	  const existing = collection ?? [];
183	  return existing.filter((item) => item.requestId !== requestId).concat(records);
184	}
185	
186	function addHours(iso, hours) {
187	  const date = new Date(iso);
188	  date.setUTCHours(date.getUTCHours() + hours);
189	  return date.toISOString();
190	}
